-- Tum kayitlari getir
SELECT * FROM students;

-- Belirli kolonlari getir
SELECT name, grade FROM students;

-- WHERE ile filtreleme
SELECT * FROM students
WHERE grade >= 70;

-- Birden fazla kosul (AND)
SELECT name, age, grade FROM students
WHERE age >= 20 AND grade >= 70;

-- OR kosulu
SELECT name, grade FROM students
WHERE grade < 60 OR grade > 90;

-- IN ile liste kontrolu
SELECT name FROM students
WHERE age IN (20, 21);

-- BETWEEN ile aralik
SELECT name, grade FROM students
WHERE grade BETWEEN 60 AND 90;

-- LIKE ile metin arama
SELECT name FROM students
WHERE name LIKE 'A%';

-- NULL kontrolu
SELECT name FROM students
WHERE phone IS NULL;
